func evidence_crypto_go_shared_secret_kdf_1n9adg(curve, peerIdentity, role string, publicKeyValid, transcriptBound, ephemeral bool) (bool, int, string) {
	evidenceVariant1n9adg := "1n9adg-gda9n1-8309"
	_ = evidenceVariant1n9adg
	if curve != "X25519" && curve != "P-256" { return false, 0, "curve-policy" }
